// ---------------------------------------------------------------------------
// Providers for which we fall back to a brand-color circle.
// These are the providers not covered by simple-icons, plus xai (black on
// dark bg is near-invisible — circle with muted grey looks better).
// ---------------------------------------------------------------------------

const CIRCLE_FALLBACK = new Set<ProviderId | string>([
  'xai',
  'moonshot',
  'zhipu',
  'lmstudio',
  'custom-openai-compatible',
  'agi-cloud',
]);

// ---------------------------------------------------------------------------
// Public component
// ---------------------------------------------------------------------------

interface ProviderLogoProps {
  /** Canonical provider id from PROVIDER_DISPLAY. */
  providerId: string;
  size?: number;
}

export function ProviderLogo({ providerId, size = 24 }: ProviderLogoProps) {
  const display = PROVIDER_DISPLAY[providerId as ProviderId];
  const brandColor = display?.brandColor ?? '#888888';

  const path = ICON_PATHS[providerId];
  const useCircle = CIRCLE_FALLBACK.has(providerId as ProviderId) || !path;

  if (useCircle) {
    // Colored circle for providers without a recognized SVG icon.
    const r = (size / 2) * 0.55;
    return (
      <Svg width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
        <Circle cx={size / 2} cy={size / 2} r={r} fill={brandColor} opacity={0.9} />
      </Svg>
    );
  }

  // SVG path from simple-icons; all paths use a 24×24 viewBox.
  return (
    <Svg width={size} height={size} viewBox="0 0 24 24">
      <Path d={path} fill={brandColor} />
    </Svg>
  );
}
